import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { consoleApi } from '../services/api';

const S = {
  page: { display: 'flex', minHeight: 'calc(100vh - 64px)', background: 'var(--color-bg)' },
  left: {
    width: '44%', minWidth: 360, flexShrink: 0, padding: '40px 32px',
    borderRight: '1px solid var(--color-stone)', overflowY: 'auto',
  },
  right: {
    flex: 1, padding: '40px 32px', background: 'var(--color-surface)',
    overflowY: 'auto', minWidth: 0,
  },
  title: { fontSize: 'var(--text-2xl)', fontWeight: 'var(--weight-bold)', color: 'var(--color-text-primary)', marginBottom: 6 },
  subtitle: { fontSize: 'var(--text-sm)', color: 'var(--color-text-muted)', marginBottom: 32 },
  label: { fontSize: 'var(--text-xs)', fontWeight: 'var(--weight-semibold)', letterSpacing: 'var(--tracking-wider)', textTransform: 'uppercase', color: 'var(--color-text-muted)', marginBottom: 8, display: 'block' },
  inputWrap: { marginBottom: 20 },
  inputRow: { display: 'flex', alignItems: 'center', gap: 8 },
  eyeBtn: { padding: '10px 12px', background: 'var(--color-surface)', border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-md)', cursor: 'pointer', fontSize: '1rem', color: 'var(--color-text-muted)', flexShrink: 0 },
  methodBadge: {
    padding: '10px 14px', background: 'var(--color-dark)', color: 'var(--color-gold)',
    borderRadius: 'var(--radius-md)', fontSize: 'var(--text-xs)', fontWeight: 'var(--weight-bold)',
    fontFamily: 'var(--font-mono)', flexShrink: 0,
  },
  quickEndpoints: { display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 20 },
  qChip: {
    padding: '4px 10px', background: 'var(--color-stone)',
    borderRadius: 'var(--radius-full)', fontSize: 10, cursor: 'pointer',
    fontFamily: 'var(--font-mono)', color: 'var(--color-text-muted)', border: 'none',
    transition: 'all 150ms',
  },
  paramsSection: { marginBottom: 20 },
  paramRow: { display: 'flex', gap: 8, marginBottom: 8, alignItems: 'center' },
  paramInput: {
    flex: 1, padding: '8px 10px', background: 'var(--color-bg)',
    border: '1px solid var(--color-stone)', borderRadius: 'var(--radius-md)',
    fontSize: 'var(--text-xs)', fontFamily: 'var(--font-mono)', outline: 'none',
    color: 'var(--color-text-primary)',
  },
  removeBtn: { background: 'none', border: 'none', cursor: 'pointer', color: 'var(--color-text-muted)', fontSize: '1rem', padding: '4px 8px' },
  addParamBtn: { background: 'none', border: '1px dashed var(--color-stone)', borderRadius: 'var(--radius-md)', padding: '6px 12px', fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)', cursor: 'pointer', width: '100%' },
  /* Snippets */
  snippetBar: { display: 'flex', gap: 4, marginTop: 24, marginBottom: 0, flexWrap: 'wrap' },
  sTab: { padding: '6px 12px', borderRadius: '6px 6px 0 0', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: 10, fontFamily: 'var(--font-mono)', color: 'var(--color-dark-muted)', transition: 'all 150ms' },
  sTabActive: { background: 'var(--color-dark)', color: '#fff' },
  snipBox: { background: 'var(--color-dark)', borderRadius: '0 6px 6px 6px', padding: '16px', overflowX: 'auto', marginBottom: 8 },
  snipPre: { fontFamily: 'var(--font-mono)', fontSize: 10, color: 'var(--color-dark-text)', lineHeight: 1.8, margin: 0, whiteSpace: 'pre' },
  /* Response */
  rTitle: { fontSize: 'var(--text-lg)', fontWeight: 'var(--weight-semibold)', color: 'var(--color-text-primary)', marginBottom: 6 },
  rMeta: { display: 'flex', gap: 12, marginBottom: 20, flexWrap: 'wrap', alignItems: 'center' },
  statusBadge: (ok) => ({
    padding: '4px 12px', borderRadius: 'var(--radius-full)', fontSize: 'var(--text-sm)',
    fontWeight: 'var(--weight-bold)', fontFamily: 'var(--font-mono)',
    background: ok ? 'var(--color-success-light)' : 'var(--color-error-light)',
    color: ok ? 'var(--color-success)' : 'var(--color-error)',
  }),
  timeBadge: { padding: '4px 10px', background: 'var(--color-stone)', borderRadius: 'var(--radius-full)', fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)' },
  jsonBox: { background: 'var(--color-dark)', borderRadius: 'var(--radius-xl)', padding: '24px', overflowX: 'auto', position: 'relative', maxHeight: 500 },
  jsonPre: { fontFamily: 'var(--font-mono)', fontSize: 'var(--text-xs)', color: 'var(--color-dark-text)', lineHeight: 1.8, margin: 0, whiteSpace: 'pre-wrap', wordBreak: 'break-all' },
  copyJsonBtn: { position: 'absolute', top: 10, right: 10, padding: '4px 10px', background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.15)', borderRadius: 6, color: 'rgba(250,250,248,0.6)', fontSize: 10, cursor: 'pointer', fontFamily: 'var(--font-sans)' },
  emptyRight: { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', gap: 16, textAlign: 'center', color: 'var(--color-text-muted)' },
};

const QUICK_ENDPOINTS = [
  '/api/v1/datasets',
  '/api/v1/datasets/world-countries/data',
  '/api/v1/solution-packs',
  '/api/v1/buildpilot/examples',
  '/api/v1/stats',
];

const SNIPPET_TABS = ['curl', 'python', 'javascript', 'fastapi', 'express'];

export default function ApiConsole() {
  const [searchParams] = useSearchParams();
  const [apiKey, setApiKey] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [endpoint, setEndpoint] = useState(searchParams.get('endpoint') || '/api/v1/datasets');
  const [params, setParams] = useState([{ key: '', value: '' }]);
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState(null);
  const [error, setError] = useState('');
  const [snippetTab, setSnippetTab] = useState('curl');
  const [copied, setCopied] = useState(false);

  const copy = (text) => { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 1800); };

  const execute = async () => {
    if (!apiKey.trim()) { setError('Please enter your API key.'); return; }
    if (!endpoint.trim().startsWith('/api/v1/')) { setError('Endpoint must start with /api/v1/'); return; }
    setError('');
    setLoading(true);
    setResponse(null);
    try {
      const paramObj = {};
      params.filter(p => p.key.trim()).forEach(p => { paramObj[p.key] = p.value; });
      const res = await consoleApi.execute(endpoint, apiKey, Object.keys(paramObj).length > 0 ? paramObj : undefined);
      setResponse(res.data);
    } catch (e) {
      setError(e.message || 'Request failed.');
    } finally {
      setLoading(false);
    }
  };

  const addParam = () => setParams(p => [...p, { key: '', value: '' }]);
  const removeParam = (i) => setParams(p => p.filter((_, j) => j !== i));
  const updateParam = (i, field, val) => setParams(p => p.map((row, j) => j === i ? { ...row, [field]: val } : row));

  const isOk = response?.status_code >= 200 && response?.status_code < 300;

  return (
    <div style={S.page} className="page-enter">
      {/* Left Panel */}
      <div style={S.left}>
        <h1 style={S.title}>API Console</h1>
        <p style={S.subtitle}>Test any OmniCore endpoint without leaving the platform.</p>

        {/* API Key */}
        <div style={S.inputWrap}>
          <label style={S.label}>API Key</label>
          <div style={S.inputRow}>
            <input id="console-api-key" type={showKey ? 'text' : 'password'} className="input"
              placeholder="omni_YourAPIKeyHere"
              value={apiKey} onChange={e => setApiKey(e.target.value)} />
            <button style={S.eyeBtn} onClick={() => setShowKey(s => !s)}>{showKey ? '🙈' : '👁️'}</button>
          </div>
        </div>

        {/* Endpoint */}
        <div style={S.inputWrap}>
          <label style={S.label}>Endpoint</label>
          <div style={S.inputRow}>
            <span style={S.methodBadge}>GET</span>
            <input id="console-endpoint" type="text" className="input" style={{ fontFamily: 'var(--font-mono)', fontSize: 'var(--text-sm)' }}
              placeholder="/api/v1/datasets"
              value={endpoint} onChange={e => setEndpoint(e.target.value)} />
          </div>
          <div style={{ ...S.quickEndpoints, marginTop: 8 }}>
            {QUICK_ENDPOINTS.map(ep => (
              <button key={ep} style={S.qChip} onClick={() => setEndpoint(ep)}
                onMouseEnter={e => { e.target.style.background = 'var(--color-gold-light)'; e.target.style.color = 'var(--color-gold-dark)'; }}
                onMouseLeave={e => { e.target.style.background = 'var(--color-stone)'; e.target.style.color = 'var(--color-text-muted)'; }}>
                {ep}
              </button>
            ))}
          </div>
        </div>

        {/* Parameters */}
        <div style={S.paramsSection}>
          <label style={S.label}>Query Parameters</label>
          {params.map((p, i) => (
            <div key={i} style={S.paramRow}>
              <input style={S.paramInput} placeholder="key" value={p.key} onChange={e => updateParam(i, 'key', e.target.value)} />
              <input style={S.paramInput} placeholder="value" value={p.value} onChange={e => updateParam(i, 'value', e.target.value)} />
              {params.length > 1 && (
                <button style={S.removeBtn} onClick={() => removeParam(i)}>✕</button>
              )}
            </div>
          ))}
          <button style={S.addParamBtn} onClick={addParam}>+ Add Parameter</button>
        </div>

        {error && <div style={{ padding: '10px 14px', background: 'var(--color-error-light)', color: 'var(--color-error)', borderRadius: 'var(--radius-md)', fontSize: 'var(--text-sm)', marginBottom: 12 }}>{error}</div>}

        <button id="console-execute-btn" className="btn btn-gold" style={{ width: '100%', fontSize: 'var(--text-base)' }}
          onClick={execute} disabled={loading}>
          {loading ? <><span className="spinner spinner-sm" style={{ borderTopColor: '#fff', borderColor: 'rgba(255,255,255,0.3)' }} /> Executing...</> : '▶ Execute'}
        </button>

        {/* Snippets (show after response) */}
        {response?.code_snippets && (
          <>
            <div style={S.snippetBar}>
              {SNIPPET_TABS.filter(t => response.code_snippets[t]).map(t => (
                <button key={t} style={{ ...S.sTab, ...(snippetTab === t ? S.sTabActive : {}) }} onClick={() => setSnippetTab(t)}>{t}</button>
              ))}
            </div>
            <div style={{ ...S.snipBox, background: 'var(--color-dark-surface)' }}>
              <pre style={{ ...S.snipPre, fontSize: 9 }}>{response.code_snippets[snippetTab]}</pre>
            </div>
          </>
        )}
      </div>

      {/* Right Panel */}
      <div style={S.right}>
        {loading ? (
          <div style={S.emptyRight}>
            <span className="spinner spinner-lg" />
            <span style={{ fontSize: 'var(--text-sm)' }}>Executing request…</span>
          </div>
        ) : !response ? (
          <div style={S.emptyRight}>
            <span style={{ fontSize: '3rem' }}>⚙️</span>
            <span style={{ fontWeight: 'var(--weight-semibold)', fontSize: 'var(--text-lg)', color: 'var(--color-text-primary)' }}>Response viewer</span>
            <span style={{ fontSize: 'var(--text-sm)', maxWidth: 260 }}>Enter your API key and endpoint, then click Execute to see the response.</span>
          </div>
        ) : (
          <>
            <div style={S.rTitle}>Response</div>
            <div style={S.rMeta}>
              <span style={S.statusBadge(isOk)}>{response.status_code} {isOk ? 'OK' : 'Error'}</span>
              <span style={S.timeBadge}>⚡ {response.response_time_ms}ms</span>
              <span style={S.timeBadge}>{response.method} {response.endpoint}</span>
            </div>
            <div style={S.jsonBox}>
              <button style={S.copyJsonBtn} onClick={() => copy(JSON.stringify(response.response_body, null, 2))}>
                {copied ? '✓' : 'Copy JSON'}
              </button>
              <pre style={S.jsonPre}>{JSON.stringify(response.response_body, null, 2)}</pre>
            </div>
            <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
              <button className="btn btn-outline btn-sm"
                onClick={() => { const blob = new Blob([JSON.stringify(response.response_body, null, 2)], { type: 'application/json' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'response.json'; a.click(); }}>
                ↓ Download JSON
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
